import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

import { ref, computed, onMounted, onUnmounted, watch, toValue, type ComputedRef, type MaybeRefOrGetter, type Ref } from 'vue'
import useEmblaCarousel from 'embla-carousel-vue'
import { useReducedMotion } from '@/components/ui/carousel/useReducedMotion'

export const DEFAULT_AUTOPLAY_DELAY = 3000

export interface UseCarouselOptions {
    loop?: MaybeRefOrGetter<boolean | undefined>
    autoplay?: MaybeRefOrGetter<boolean | undefined>
    autoplayDelay?: MaybeRefOrGetter<number | undefined>
    /** autoplay 状态变化回调 */
    onAutoplayChange?: (enabled: boolean) => void
    /** autoplayDelay 变化后 autoplay 重启回调 */
    onAutoplayDelayChange?: () => void
}

export interface UseCarouselReturn {
    emblaRef: Ref<HTMLElement | undefined>
    selectedIndex: Ref<number>
    scrollSnaps: Ref<number[]>
    canScrollPrev: ComputedRef<boolean>
    canScrollNext: ComputedRef<boolean>
    scrollPrev: () => void
    scrollNext: () => void
    scrollTo: (index: number) => void
    startAutoplay: () => void
    stopAutoplay: () => void
}

export function useCarousel(options: UseCarouselOptions = {}): UseCarouselReturn {
    const prefersReducedMotion = useReducedMotion()

    const [emblaRef, emblaApi] = useEmblaCarousel({ loop: toValue(options.loop) ?? false })

    const selectedIndex = ref(0)
    const scrollSnaps = ref<number[]>([])
    let autoplayTimer: ReturnType<typeof setInterval> | null = null

    const canScrollPrev = computed(() => (toValue(options.loop) ?? false) || selectedIndex.value > 0)
    const canScrollNext = computed(() => (toValue(options.loop) ?? false) || selectedIndex.value < scrollSnaps.value.length - 1)

    function onInit() {
        if (!emblaApi.value) return
        scrollSnaps.value = emblaApi.value.scrollSnapList()
        selectedIndex.value = emblaApi.value.selectedScrollSnap()
    }

    function onSelect() {
        if (!emblaApi.value) return
        selectedIndex.value = emblaApi.value.selectedScrollSnap()
    }

    function scrollPrev() {
        emblaApi.value?.scrollPrev()
    }

    function scrollNext() {
        emblaApi.value?.scrollNext()
    }

    function scrollTo(index: number) {
        emblaApi.value?.scrollTo(index)
    }

    function startAutoplay() {
        stopAutoplay()
        if (!toValue(options.autoplay) || prefersReducedMotion.value) return
        autoplayTimer = setInterval(() => {
            if (emblaApi.value && scrollSnaps.value.length > 0) {
                if (!(toValue(options.loop) ?? false) && selectedIndex.value === scrollSnaps.value.length - 1) {
                    stopAutoplay()
                } else {
                    emblaApi.value.scrollNext()
                }
            }
        }, toValue(options.autoplayDelay) ?? DEFAULT_AUTOPLAY_DELAY)
    }

    function stopAutoplay() {
        if (autoplayTimer) {
            clearInterval(autoplayTimer)
            autoplayTimer = null
        }
    }

    let cachedApi: NonNullable<typeof emblaApi.value> | null = null

    onMounted(() => {
        if (!emblaApi.value) return
        cachedApi = emblaApi.value
        cachedApi.on('init', onInit)
        cachedApi.on('select', onSelect)
        cachedApi.on('reInit', onInit)
        if (prefersReducedMotion.value) {
            cachedApi.reInit({ duration: 0 })
        }
        onInit()
        startAutoplay()
    })

    watch(() => toValue(options.autoplay), (val) => {
        if (val) {
            startAutoplay()
            options.onAutoplayChange?.(true)
        } else {
            stopAutoplay()
            options.onAutoplayChange?.(false)
        }
    })

    watch(() => toValue(options.loop), () => {
        if (emblaApi.value) emblaApi.value.reInit({ loop: toValue(options.loop) ?? false })
    })

    watch(() => toValue(options.autoplayDelay), () => {
        if (toValue(options.autoplay)) {
            startAutoplay()
            options.onAutoplayDelayChange?.()
        }
    })

    watch(prefersReducedMotion, (reduced) => {
        if (!emblaApi.value) return
        if (reduced) {
            stopAutoplay()
            emblaApi.value.reInit({ duration: 0 })
        } else {
            emblaApi.value.reInit({})
            if (toValue(options.autoplay)) startAutoplay()
        }
    })

    onUnmounted(() => {
        stopAutoplay()
        if (cachedApi) {
            cachedApi.off('init', onInit)
            cachedApi.off('select', onSelect)
            cachedApi.off('reInit', onInit)
        }
    })

    return {
        emblaRef,
        selectedIndex,
        scrollSnaps,
        canScrollPrev,
        canScrollNext,
        scrollPrev,
        scrollNext,
        scrollTo,
        startAutoplay,
        stopAutoplay,
    }
}

import { ref, computed, onUnmounted, toValue, type MaybeRefOrGetter } from 'vue'
import { DEFAULT_AUTOPLAY_INTERVAL_MS } from '@/lib/defaults'
import { useCarousel, type UseCarouselOptions } from '@/components/ui/carousel/useCarousel'

const DEFAULT_PROGRESS_INTERVAL = 50

export interface UseCarouselEnhancedOptions extends UseCarouselOptions {
    /** 是否启用进度追踪（默认 false） */
    trackProgress?: MaybeRefOrGetter<boolean | undefined>
    /** 进度更新间隔（默认 50ms） */
    progressInterval?: MaybeRefOrGetter<number | undefined>
}

export function useCarouselEnhanced(options: UseCarouselEnhancedOptions = {}) {
    // 复用基础 composable，通过回调同步进度条
    const carousel = useCarousel({
        ...options,
        onAutoplayChange: (enabled) => {
            if (enabled) {
                startProgressTimer()
            } else {
                stopProgressTimer()
            }
            options.onAutoplayChange?.(enabled)
        },
        onAutoplayDelayChange: () => {
            startProgressTimer()
            options.onAutoplayDelayChange?.()
        },
    })

    // 增强功能：进度追踪
    const autoplayProgress = ref(0)
    let progressTimer: ReturnType<typeof setInterval> | null = null

    const progressUpdateInterval = computed(() =>
        toValue(options.progressInterval) ?? DEFAULT_PROGRESS_INTERVAL
    )

    function startProgressTimer() {
        stopProgressTimer()
        if (!toValue(options.trackProgress)) return

        const delay = toValue(options.autoplayDelay) ?? DEFAULT_AUTOPLAY_INTERVAL_MS
        const interval = progressUpdateInterval.value
        const steps = delay / interval

        progressTimer = setInterval(() => {
            autoplayProgress.value += 100 / steps
            if (autoplayProgress.value >= 100) {
                autoplayProgress.value = 0
            }
        }, interval)
    }

    function stopProgressTimer() {
        if (progressTimer) {
            clearInterval(progressTimer)
            progressTimer = null
        }
        autoplayProgress.value = 0
    }

    // 增强版自动播放控制（集成进度追踪）
    function startAutoplay() {
        carousel.startAutoplay()
        startProgressTimer()
    }

    function stopAutoplay() {
        carousel.stopAutoplay()
        stopProgressTimer()
    }

    onUnmounted(() => {
        stopProgressTimer()
    })

    return {
        // 基础功能（来自 useCarousel）
        emblaRef: carousel.emblaRef,
        selectedIndex: carousel.selectedIndex,
        scrollSnaps: carousel.scrollSnaps,
        canScrollPrev: carousel.canScrollPrev,
        canScrollNext: carousel.canScrollNext,
        scrollPrev: carousel.scrollPrev,
        scrollNext: carousel.scrollNext,
        scrollTo: carousel.scrollTo,

        // 增强功能
        autoplayProgress,
        startAutoplay,
        stopAutoplay,
    }
}

